code_examples:
# NGINX round-robin load balancing config
upstream backend {
    server app1.example.com:8080;
    server app2.example.com:8080;
    server app3.example.com:8080;
}

server {
    listen 80;
    location / {
        proxy_pass http://backend;
    }
}

# Least connections strategy
upstream backend {
    least_conn;
    server app1.example.com:8080;
    server app2.example.com:8080;
}
